import React, { useState } from 'react';
import { translations } from '../translations';
import { Language } from '../types';
import { Phone, Mail, MapPin, Send } from 'lucide-react';

const Contact: React.FC<{ lang: Language }> = ({ lang }) => {
  const t = translations[lang];
  const [formData, setFormData] = useState({ name: '', email: '', message: '' });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    alert(lang === 'am' ? 'መልዕክትዎ ተልኳል! እናመሰግናለን።' : 'Message sent! Thank you.');
    setFormData({ name: '', email: '', message: '' });
  };

  return (
    <div className="py-16 bg-white">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <h1 className="text-4xl font-bold text-blue-900 mb-12 text-center">{t.contact.title}</h1>

        <div className="grid lg:grid-cols-2 gap-16">
          {/* Contact Info & Map */}
          <div className="space-y-12">
            <div className="space-y-6">
              <h2 className="text-2xl font-bold text-gray-900">{lang === 'am' ? 'መረጃዎን ያግኙ' : 'Get in Touch'}</h2>
              <div className="flex items-center gap-4 text-gray-700">
                <div className="w-10 h-10 bg-blue-100 rounded-full flex items-center justify-center shrink-0">
                  <Phone size={20} className="text-blue-600" />
                </div>
                <span>{t.contact.phone}</span>
              </div>
              <div className="flex items-center gap-4 text-gray-700">
                <div className="w-10 h-10 bg-red-100 rounded-full flex items-center justify-center shrink-0">
                  <Mail size={20} className="text-red-600" />
                </div>
                <span>info@woloseferchurch.org</span>
              </div>
              <div className="flex items-center gap-4 text-gray-700">
                <div className="w-10 h-10 bg-yellow-100 rounded-full flex items-center justify-center shrink-0">
                  <MapPin size={20} className="text-yellow-600" />
                </div>
                <span>{t.about.address}</span>
              </div>
            </div>

            <div className="space-y-4">
              <h3 className="text-xl font-bold text-gray-900">{t.contact.findUs}</h3>
              <div className="w-full h-80 bg-gray-200 rounded-2xl overflow-hidden border border-gray-100 relative">
                {/* Simplified Map Embed UI */}
                <iframe 
                  className="w-full h-full grayscale-[0.2] contrast-[1.1]"
                  src={`https://www.google.com/maps/embed/v1/place?key=REPLACE_WITH_YOUR_KEY&q=XQQF%2B9GJ`}
                  style={{ border: 0 }}
                  allowFullScreen
                  loading="lazy"
                  title="Church Location"
                ></iframe>
                {/* Overlay text since we don't have a real API key for the iframe in this demo */}
                <div className="absolute inset-0 flex items-center justify-center bg-blue-900/10 pointer-events-none">
                    <div className="bg-white/90 p-4 rounded-lg shadow-xl text-center">
                        <p className="font-bold text-blue-900">Plus Code: XQQF+9GJ</p>
                        <p className="text-xs text-gray-600">Kirkos, Addis Ababa</p>
                    </div>
                </div>
              </div>
            </div>
          </div>

          {/* Contact Form */}
          <div className="bg-blue-50 p-8 rounded-3xl border border-blue-100">
            <form onSubmit={handleSubmit} className="space-y-6">
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-2">{t.contact.name}</label>
                <input 
                  type="text" 
                  value={formData.name}
                  onChange={(e) => setFormData({...formData, name: e.target.value})}
                  required
                  className="w-full px-4 py-3 rounded-xl border border-blue-200 focus:outline-none focus:ring-2 focus:ring-blue-500 bg-white"
                  placeholder={lang === 'am' ? 'ሙሉ ስም' : 'Your Name'}
                />
              </div>
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-2">{t.contact.email}</label>
                <input 
                  type="email" 
                  value={formData.email}
                  onChange={(e) => setFormData({...formData, email: e.target.value})}
                  required
                  className="w-full px-4 py-3 rounded-xl border border-blue-200 focus:outline-none focus:ring-2 focus:ring-blue-500 bg-white"
                  placeholder="name@email.com"
                />
              </div>
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-2">{t.contact.message}</label>
                <textarea 
                  rows={5}
                  value={formData.message}
                  onChange={(e) => setFormData({...formData, message: e.target.value})}
                  required
                  className="w-full px-4 py-3 rounded-xl border border-blue-200 focus:outline-none focus:ring-2 focus:ring-blue-500 bg-white"
                  placeholder={lang === 'am' ? 'መልዕክትዎን እዚህ ይጻፉ...' : 'Write your message here...'}
                ></textarea>
              </div>
              <button 
                type="submit"
                className="w-full flex items-center justify-center gap-2 bg-blue-600 text-white font-bold py-4 rounded-xl hover:bg-blue-700 transition-all transform hover:scale-[1.02] shadow-lg"
              >
                <Send size={20} />
                {t.contact.send}
              </button>
            </form>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Contact;

