              >
                {isDarkMode ? <Sun size={18} /> : <Moon size={18} />}
              </button>

              <button
                onClick={toggleLang}
                className="flex items-center gap-2 bg-blue-900 text-white px-4 py-2 rounded-2xl hover:bg-blue-800 transition-all font-black text-xs shadow-md"
