const Header = ({ 
  lang, 
  setLang, 
  isDarkMode, 
  toggleDarkMode,
  isLoggedIn,
  setIsLoggedIn
}: { 
  lang: Language, 
  setLang: (l: Language) => void,
  isDarkMode: boolean,
  toggleDarkMode: () => void,
  isLoggedIn: boolean,
  setIsLoggedIn: (b: boolean) => void
}) => {
  const [isOpen, setIsOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const t = translations[lang];
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const toggleLang = () => {
    setLang(lang === 'am' ? 'en' : 'am');
  };

  const navItems = [
    { name: t.nav.home, path: '/' },
    { name: t.nav.about, path: '/about' },
    { name: t.nav.services, path: '/services' },
    { name: t.nav.gallery, path: '/gallery' },
    { name: t.nav.contact, path: '/contact' },
  ];

  const handleAuthAction = () => {
    setIsLoggedIn(!isLoggedIn);
    setIsOpen(false);
  };

  return (
    <nav className={`fixed w-full top-0 z-50 transition-all duration-500 ${
      scrolled 
      ? 'bg-white/90 dark:bg-gray-900/90 backdrop-blur-md shadow-lg py-2' 
      : 'bg-white dark:bg-gray-900 py-4'
    }`}>
      <div className="max-w-[1400px] mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center h-16">
          <div className="flex items-center">
            <Link to="/" className="flex-shrink-0 flex items-center gap-3 group">
              <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center text-white font-bold text-xl border-2 border-yellow-400 transform group-hover:rotate-12 transition-transform shadow-lg">
                W
              </div>
              <div className="flex flex-col">
                <span className="font-black text-blue-900 dark:text-blue-400 tracking-tighter leading-none">
                  {lang === 'am' ? 'ወሎ ሰፈር' : 'WOLO SEFER'}
                </span>
                <span className="text-[10px] font-bold text-gray-500 dark:text-gray-400 uppercase tracking-[0.2em]">
                  {lang === 'am' ? 'ቅድስት ማርያም' : 'ST. MARY'}
                </span>
              </div>
            </Link>
          </div>

          <div className="hidden md:flex items-center space-x-1">
            {navItems.map((item) => (
              <Link
                key={item.path}
                to={item.path}
                className={`relative px-4 py-2 text-sm font-black transition-all rounded-full ${
                  location.pathname === item.path 
                  ? 'text-blue-600 bg-blue-50 dark:text-blue-400 dark:bg-blue-900/30' 
                  : 'text-gray-600 dark:text-gray-300 hover:text-blue-600 dark:hover:text-blue-400 hover:bg-gray-50 dark:hover:bg-gray-800'
                }`}
              >
                {item.name}
              </Link>
            ))}

            <div className="flex items-center gap-2 ml-4 pl-4 border-l border-gray-100 dark:border-gray-800">
              {/* Auth Buttons */}
              {!isLoggedIn ? (
                <>
                  <button 
                    onClick={handleAuthAction}
                    className="flex items-center gap-2 px-4 py-2 text-xs font-black text-blue-700 dark:text-blue-300 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-xl transition-all"
                  >
                    <LogIn size={14} />
                    {t.auth.logIn}
                  </button>
                  <button 
                    onClick={handleAuthAction}
                    className="flex items-center gap-2 bg-yellow-400 text-blue-900 px-4 py-2 rounded-xl hover:bg-yellow-300 transition-all font-black text-xs shadow-sm"
                  >
                    <UserPlus size={14} />
                    {t.auth.signUp}
                  </button>
                </>
              ) : (
                <button 
                  onClick={handleAuthAction}
                  className="flex items-center gap-2 px-4 py-2 text-xs font-black text-red-600 dark:text-red-400 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-xl transition-all"
                >
                  <LogOut size={14} />
                  {t.auth.signOut}
                </button>
              )}

              <button
                onClick={toggleDarkMode}
                className="p-2.5 rounded-2xl bg-gray-100 dark:bg-gray-800 text-gray-600 dark:text-gray-300 hover:scale-110 active:scale-95 transition-all shadow-sm"
              >
                {isDarkMode ? <Sun size={18} /> : <Moon size={18} />}
              </button>

              <button
                onClick={toggleLang}
                className="flex items-center gap-2 bg-blue-900 text-white px-4 py-2 rounded-2xl hover:bg-blue-800 transition-all font-black text-xs shadow-md"
              >
                <Globe size={14} />
                {lang === 'am' ? 'ENGLISH' : 'አማርኛ'}
              </button>
            </div>
          </div>

          <div className="md:hidden flex items-center gap-3">
             <button onClick={toggleDarkMode} className="p-2 rounded-xl bg-gray-100 dark:bg-gray-800">
                {isDarkMode ? <Sun size={18} /> : <Moon size={18} />}
              </button>
            <button
              onClick={() => setIsOpen(!isOpen)}
              className="p-2 rounded-xl bg-blue-900 text-white shadow-lg"
            >
              {isOpen ? <X size={20} /> : <Menu size={20} />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Menu */}
      <div className={`md:hidden absolute w-full bg-white dark:bg-gray-900 border-b border-gray-100 dark:border-gray-800 transition-all duration-300 ${isOpen ? 'top-full opacity-100 shadow-2xl' : '-top-[500px] opacity-0 pointer-events-none'}`}>
        <div className="px-4 pt-4 pb-8 space-y-2">
          {navItems.map((item) => (
            <Link
              key={item.path}
              to={item.path}
              onClick={() => setIsOpen(false)}
              className="block px-4 py-4 rounded-2xl text-lg font-black text-gray-700 dark:text-gray-200 hover:bg-blue-50 dark:hover:bg-gray-800"
            >
              {item.name}
            </Link>
          ))}

          <div className="grid grid-cols-2 gap-2 pt-4 border-t border-gray-100 dark:border-gray-800">
            {!isLoggedIn ? (
              <>
                <button 
                  onClick={handleAuthAction}
                  className="flex items-center justify-center gap-2 py-4 rounded-2xl text-sm font-black text-gray-700 dark:text-gray-200 bg-gray-50 dark:bg-gray-800"
                >
                  <LogIn size={18} />
                  {t.auth.logIn}
                </button>
                <button 
                  onClick={handleAuthAction}
                  className="flex items-center justify-center gap-2 py-4 rounded-2xl text-sm font-black text-blue-900 bg-yellow-400"
                >
                  <UserPlus size={18} />
                  {t.auth.signUp}
                </button>
              </>
            ) : (
              <button 
                onClick={handleAuthAction}
                className="col-span-2 flex items-center justify-center gap-2 py-4 rounded-2xl text-sm font-black text-white bg-red-600"
              >
                <LogOut size={18} />
                {t.auth.signOut}
              </button>
            )}
          </div>

          <button
            onClick={() => { toggleLang(); setIsOpen(false); }}
            className="w-full text-left flex items-center gap-3 px-4 py-4 rounded-2xl text-lg font-black text-blue-600 dark:text-blue-400 bg-blue-50 dark:bg-blue-900/30"
          >
            <Globe size={20} />
            {lang === 'am' ? 'English' : 'አማርኛ'}
          </button>
        </div>
      </div>
    </nav>
  );
};

const Footer = ({ lang }: { lang: Language }) => {
