          <div className="flex gap-2 pt-2">
            <button onClick={() => {setLang(lang === 'am' ? 'en' : 'am'); setIsOpen(false);}} className="flex-1 flex items-center justify-center gap-2 py-4 rounded-2xl bg-blue-900 text-white font-black text-sm uppercase"><Globe size={18}/>{lang === 'am' ? 'English' : 'አማርኛ'}</button>
            <button onClick={() => {toggleDarkMode(); setIsOpen(false);}} className="px-6 rounded-2xl bg-gray-100 dark:bg-gray-800 text-gray-600 dark:text-gray-300">{isDarkMode ? <Sun size={20}/> : <Moon size={20}/>}</button>
          </div>
        </div>
      </div>
    </nav>
  );
};

