const CarouselCard: React.FC<{ 
  albumAm: GalleryAlbumTranslation; 
  albumEn: GalleryAlbumTranslation; 
  images: string[]; 
  lang: Language 
}> = ({ albumAm, albumEn, images, lang }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [loadedImages, setLoadedImages] = useState<Record<string, boolean>>({});

  const nextSlide = () => setCurrentIndex((prev) => (prev + 1) % images.length);
  const prevSlide = () => setCurrentIndex((prev) => (prev - 1 + images.length) % images.length);

  const currentAm = albumAm.images[currentIndex];
  const currentEn = albumEn.images[currentIndex];
  const currentImageSrc = images[currentIndex];
  const isLoaded = !!loadedImages[currentImageSrc];

  return (
    <div className="group bg-white dark:bg-gray-800 rounded-[2.5rem] shadow-sm hover:shadow-2xl transition-all duration-500 overflow-hidden border border-gray-100 dark:border-gray-700 flex flex-col h-full">
      <div className="relative aspect-[4/3] overflow-hidden bg-gray-100 dark:bg-gray-900">
        {!isLoaded && (
          <div className="absolute inset-0 flex flex-col items-center justify-center z-10 bg-gray-100 dark:bg-gray-900">
            <Loader2 className="w-10 h-10 text-blue-600 dark:text-blue-400 animate-spin mb-2" />
            <span className="text-[10px] font-black tracking-widest text-gray-400 dark:text-gray-500 uppercase">
              {lang === 'am' ? 'በመጫን ላይ...' : 'Loading...'}
            </span>
          </div>
        )}
        <div className="w-full h-full relative">
          {images.map((src, idx) => (
            <img
              key={idx}
              src={src}
              onLoad={() => setLoadedImages(p => ({ ...p, [src]: true }))}
              className={`absolute inset-0 w-full h-full object-cover transition-all duration-700 ease-in-out ${
                idx === currentIndex && loadedImages[src] ? 'opacity-100 scale-100' : 'opacity-0 scale-110'
              }`}
              alt={currentAm.label}
            />
          ))}
        </div>
        <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-transparent opacity-40"></div>
        {images.length > 1 && (
          <>
            <button onClick={(e) => { e.preventDefault(); prevSlide(); }} className="absolute left-4 top-1/2 -translate-y-1/2 w-10 h-10 bg-white/20 backdrop-blur-md rounded-full flex items-center justify-center text-white hover:bg-white hover:text-blue-900 transition-all opacity-0 group-hover:opacity-100 z-20"><ChevronLeft size={24} /></button>
            <button onClick={(e) => { e.preventDefault(); nextSlide(); }} className="absolute right-4 top-1/2 -translate-y-1/2 w-10 h-10 bg-white/20 backdrop-blur-md rounded-full flex items-center justify-center text-white hover:bg-white hover:text-blue-900 transition-all opacity-0 group-hover:opacity-100 z-20"><ChevronRight size={24} /></button>
          </>
        )}
        <div className="absolute top-6 left-6 bg-blue-900/80 backdrop-blur-md text-white px-3 py-1 rounded-full text-[10px] font-black z-20 border border-white/20">
          {currentIndex + 1} / {images.length}
        </div>
      </div>

      <div className="p-8 flex-grow flex flex-col">
        <div className="flex items-center gap-2 mb-4">
          <div className="w-8 h-8 rounded-lg bg-blue-50 dark:bg-blue-900/30 flex items-center justify-center">
            <Camera size={16} className="text-blue-600 dark:text-blue-400" />
          </div>
